actions.script:
List wList = ec.web.session.getAttribute("wizardResultList")
if (wList != null && itemIndex) {
    int idx = itemIndex as int
    if (idx >= 0 && idx < wList.size()) {
        wList.remove(idx)
    }
    ec.web.session.setAttribute("wizardResultList", wList)
}

pre-actions.script:
// Handling edit mode via schemaName or jsonSchemaId
def currentSessionId = ec.web.session.getAttribute("wizardSchemaId") ?: ec.web.session.getAttribute("wizardSchemaName")
def incomingId = jsonSchemaId ?: schemaName

// Reload if ID changed or list missing
if (incomingId && (currentSessionId != incomingId || !ec.web.session.getAttribute("wizardResultList"))) {
    // Purge cache first
    ec.web.session.removeAttribute("wizardResultList")
    ec.web.session.removeAttribute("wizardSchemaName")
    ec.web.session.removeAttribute("wizardSchemaId")

    // If we only have ID, look up schemaName for display
    if (jsonSchemaId && !schemaName) {
        def schema = ec.entity.find("darpan.reconciliation.JsonSchema").condition("jsonSchemaId", jsonSchemaId).one()
        if (schema) schemaName = schema.schemaName
    }

    // Load schema
    def result = ec.service.sync().name("JsonSchemaServices.flatten#JsonSchema")
        .parameter("schemaName", schemaName) 
        .parameter("jsonSchemaId", jsonSchemaId)
        .call()

    if (result.fieldList) {
        ec.web.session.setAttribute("wizardResultList", result.fieldList)
        if (jsonSchemaId) ec.web.session.setAttribute("wizardSchemaId", jsonSchemaId)
        if (schemaName) ec.web.session.setAttribute("wizardSchemaName", schemaName)

        context.resultList = result.fieldList
        context.schemaName = schemaName 
    }
} else {
    // Load from session
    if (ec.web.session.getAttribute("wizardResultList")) {
        context.resultList = ec.web.session.getAttribute("wizardResultList")
    }
    if (ec.web.session.getAttribute("wizardSchemaName")) {
         context.schemaName = ec.web.session.getAttribute("wizardSchemaName")
    }
     if (ec.web.session.getAttribute("wizardSchemaId")) {
         context.jsonSchemaId = ec.web.session.getAttribute("wizardSchemaId")
    }
}
// Ensure schemaName is available for title if not passed in param but loaded in session
if (!schemaName && context.schemaName) schemaName = context.schemaName
